prompt.en:
The following program is executed, in which we assume that the fork() call does not fail, and the 'cmd' program returns value 0 only if it executes successfully. Check ALL the true statements below. Observation: all necessary #include declarations are considered included. (1p)

```c
int main(int argc, char *argv[]) {
    int status;
    switch( fork() ) {
        case -1: perror("Error at fork"); return 1;
        case 0: execlp("cmd", "cmd", ..., NULL); printf("1"); break;
        default: wait(&status);
            if( WIFEXITED(status) ) {
                switch( WEXITSTATUS(status) ) {
                    case 0 : printf("2"); break;
                    case 1 : printf("3"); break;
                    default: printf("4"); break;
                }
            } else printf("5");
            return 0;
    }
    return 2;
}
```

