prompt.en:
Consider the program in the figure. Specify what message will be displayed on the screen following its execution. Also check the Other option, where you should write the justification for the choice made. (2p)

```c
int main()
{
    int fdp, fdc, pid, nr;
    if (-1 == mkfifo("fifo_EFIA30", 0600)) { perror("mkfifo"); exit(1); }
    fdp = open("fifo_EFIA30", O_WRONLY);
    if (-1 == fdp) { perror("open1"); exit(2); }

    if (-1 == (pid = fork())) { perror("fork"); exit(3); }
    if (pid == 0) {
        char buffer[100];
        fdc = open("fifo_EFIA30", O_RDONLY);
        if (-1 == fdc) { perror("open2"); exit(4); }
        if (14 == read(fdc, buffer, 13+1) )
            printf("Citire reusita integral\n");
        else
            printf("Probleme la citire\n");
        return 0;
    }
    char* text="Salut, fiule!";
    nr = write(fdp, text, strlen(text)+1);
    if (-1 == nr) { printf("Scriere esuata\n"); exit(5); }
    wait(NULL);
}
```

